const calcScore=(p)=>{
  const s1=Math.min(p.deliveries/500*30,30);
  const s2=p.campanhas*15;
  const s3=p.mesesNaBase*2;
  const s4=p.contrato.status==="assinado"?20:0;
  const s5=p.engajamento*5;
  return Math.min(Math.round(s1+s2+s3+s4+s5),100);
};
